class Playground {
    async run(inputs) {
        const inputStr = inputs[0] || '1, 2, 3, null, null, 4, 5';
        const vals = inputStr.split(',').map(v => {
            v = v.trim();
            return (v === 'null' || v === '') ? null : parseInt(v);
        });

        this.log('Initializing Tree...');
        this.tree.init(vals);
        await this.await();

        // BFS
        this.log('Starting BFS Traversal...');
        this.output.init([]);
        this.queue.init([]);

        const root = this.tree.getRoot();
        if (!root) return;

        this.queue.enqueue(root.val);
        // We need to track actual nodes for children, so we'll use a local queue of nodes
        // but visualization queue will show values.
        const q = [root];

        this.tree.highlight(root.id, '#ec4899'); // Pink start
        await this.await();

        while (q.length > 0) {
            const curr = q.shift();
            this.queue.dequeue();

            this.log(`Visiting ${curr.val}`);
            this.tree.highlight(curr.id, '#10b981'); // Green visited
            this.output.push(curr.val);
            await this.await();

            if (curr.left) {
                this.log(`Found left child ${curr.left.val}`);
                this.tree.highlight(curr.left.id, '#f59e0b'); // Orange pending
                this.queue.enqueue(curr.left.val);
                q.push(curr.left);
                await this.await();
            }
            if (curr.right) {
                this.log(`Found right child ${curr.right.val}`);
                this.tree.highlight(curr.right.id, '#f59e0b'); // Orange pending
                this.queue.enqueue(curr.right.val);
                q.push(curr.right);
                await this.await();
            }
        }
        this.log('BFS Complete.');
        await this.await();

        // DFS (Preorder)
        this.log('Starting DFS (Preorder) using Stack...');
        this.tree.clearHighlights();
        this.output.init([]);
        this.stack.init([]);

        const s = [root];
        this.stack.push(root.val);
        this.tree.highlight(root.id, '#ec4899');
        await this.await();

        while (s.length > 0) {
            const curr = s.pop();
            this.stack.pop();

            this.log(`Visiting ${curr.val}`);
            this.tree.highlight(curr.id, '#10b981');
            this.output.push(curr.val);
            await this.await();

            // Push right first so left is processed first
            if (curr.right) {
                 this.log(`Pushing right child ${curr.right.val}`);
                 this.tree.highlight(curr.right.id, '#f59e0b');
                 this.stack.push(curr.right.val);
                 s.push(curr.right);
                 await this.await();
            }
            if (curr.left) {
                 this.log(`Pushing left child ${curr.left.val}`);
                 this.tree.highlight(curr.left.id, '#f59e0b');
                 this.stack.push(curr.left.val);
                 s.push(curr.left);
                 await this.await();
            }
        }

        this.log('DFS Complete.');
    }
}
